import React from "react";
import { InputNumber, type InputNumberProps } from "primereact/inputnumber";
import type { IKitsInputNumber } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useSeparator } from "../../../factory";
import {Icon, useComponentDefaults, useKitsTheme, useResolvedStyle} from "../../../";

const KitsInputNumber = ({ ref, ...rawProps }: IKitsInputNumber) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Input', rawProps);
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});

    const { resolveToken } = useKitsTheme();
    const primaryColor = resolveToken('brand.500');
    const borderColor = resolveToken('border');

    const {
        id, label, required, value, errors, hideError, invalid,
        isFloatedLabel, disabled, helperText, inputSize,
        localProps,
        onChange,
        attached,
        containerStyle,
        ...rest
    } = props;

    const { nativeProps } = useSeparator<InputNumberProps>(rest);

    const Element = <InputNumber
        ref={ref as any}
        inputStyle={{ borderRadius: 0, border:'none', ...(resolvedRootStyle || resolvedThemeStyle) }}
        value={value}
        disabled={disabled}
        {...nativeProps}
        {...(localProps as any)}
        onValueChange={(e: any) => onChange?.(e)}
        incrementButtonIcon={<Icon name={'chevron-up'} size={'xl'} /> }
        decrementButtonIcon={<Icon name={'chevron-down'} size={'xl'} /> }
        pt={{
            decrementButton:{
                style:{
                    backgroundColor:primaryColor,
                    border:'none'
                },
            },
            incrementButton:{
                style:{
                    backgroundColor:primaryColor,
                    border:'none'
                }
            }
        }}
    />;

    if (attached) {
        return Element;
    }

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            required={required}
            disabled={disabled}
            inputSize={inputSize}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsInputNumber;
